mapper.select:
SELECT COUNT(1)
FROM order_detail od

INNER JOIN `order` o ON o.id = od.order_id
WHERE od.museum_id = #{museumId}
  AND od.activity_id = #{activityId}
  AND od.activity_schedule_id = #{activityScheduleId}
  AND o.appointment_date = #{appointmentDate}


  AND o.order_status IN

      #{status}




  AND od.order_status IN

      #{status}

select o.unionpay_order_no trade_no
from `order` o inner join order_detail od on o.id = od.order_id
where od.pay_success_time between #{lastMonthStart} and #{lastMonthEnd}
  and od.refund_time between #{currentMonthStart} and #{currentMonthEnd}
  and od.museum_id = #{museumId}
group by o.unionpay_order_no
